import os, re, sys, time, threading, subprocess
PROMPT = '%'
MARK = "__CLITEST_DONE_MARKER__"

def parse_blocks(text):
    lines = text.split('\n'); blocks=[]; i=0
    while i < len(lines):
        if re.match(r'^\s*```', lines[i]):
            lang=lines[i].strip()[3:].strip(); i+=1; buf=[]
            while i < len(lines) and not re.match(r'^\s*```\s*$', lines[i]):
                buf.append(lines[i]); i+=1
            i+=1
            if not lang or 'zsh' in lang or 'sh' in lang:
                blocks.append(buf)
        else: i+=1
    return blocks

def parse_tests(block):
    tests=[]; cur_cmd=None; cur_exp=[]; cur_exit=None
    def flush():
        nonlocal cur_cmd
        if cur_cmd is not None: tests.append((cur_cmd,list(cur_exp),cur_exit))
        cur_cmd=None; cur_exp=[]; cur_exit=None
    for ln in block:
        if ln.startswith(PROMPT+' '):
            flush(); cur_cmd=ln[2:]; cur_exp=[]; cur_exit=None
        elif ln==PROMPT:
            flush(); cur_cmd=''; cur_exp=[]; cur_exit=None
        elif ln.strip().startswith('#=>'):
            m=re.match(r'--exit\s+(\S+)', ln.strip()[2:].strip())
            if m: cur_exit=m.group(1)
        else:
            if cur_cmd is not None: cur_exp.append(ln)
    flush(); return tests

class Shell:
    def __init__(self):
        self.p = subprocess.Popen(['zsh','-f'], stdin=subprocess.PIPE,
            stdout=subprocess.PIPE, stderr=subprocess.STDOUT, bufsize=0)
        self.buf=''
        self.lock=threading.Lock()
        self.reader=threading.Thread(target=self._read, daemon=True)
        self.reader.start()
    def _read(self):
        while True:
            d=os.read(self.p.stdout.fileno(),4096)
            if not d: break
            with self.lock:
                self.buf+=d.decode(errors='replace')
    def run(self, cmd):
        wrapper = '( ' + cmd + '\n) ; printf "\\n%s:%s\\n" ' + MARK + ' "$?"\n'
        with self.lock:
            self.buf=''
        self.p.stdin.write(wrapper.encode()); self.p.stdin.flush()
        end=time.time()+20
        while time.time()<end:
            with self.lock:
                if MARK+':' in self.buf:
                    break
            time.sleep(0.01)
        with self.lock:
            text=self.buf
        idx=text.rfind(MARK+':')
        out=text[:idx]
        rest=text[idx+len(MARK)+1:]
        m=re.search(r'(-?\d+)', rest)
        ec=int(m.group(1)) if m else 0
        if out.endswith('\n'): out=out[:-1]
        return out, ec
    def close(self):
        try: self.p.stdin.close()
        except: pass
        try: self.p.wait(timeout=2)
        except: pass

def norm(lines):
    lines=list(lines)
    while lines and lines[-1].strip()=='': lines.pop()
    return lines

def main():
    path=sys.argv[1]; text=open(path).read(); blocks=parse_blocks(text)
    sh=Shell(); sh.run('cd /app')
    total=passed=0; fails=[]
    for bi,block in enumerate(blocks):
        for cmd,exp,exitc in parse_tests(block):
            total+=1
            out,ec=sh.run(cmd)
            ok = norm(out.split('\n'))==norm(exp)
            if exitc is not None: ok = ok and ec==int(exitc)
            if ok: passed+=1
            else: fails.append((bi,cmd,exp,out.split('\n'),exitc,ec))
    sh.close()
    print(f"PASS {passed}/{total}")
    for bi,cmd,exp,out,exitc,ec in fails:
        print("="*60); print(f"BLOCK {bi} CMD: {cmd}")
        if exitc is not None: print(f"  expected exit {exitc}, got {ec}")
        print("  --- expected ---"); [print("  | "+l) for l in norm(exp)]
        print("  --- got ---"); [print("  > "+l) for l in norm(out)]
    return 0 if not fails else 1

sys.exit(main())
